1	const PROCESSING_FEE = 5;
2	
3	const BASE_PRICE_BY_TYPE: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	};
8	
9	type Item = { type: string };
10	type Step = { op: "quote"; items: Item[] };
11	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
12	
13	const itemBasePrice = (item: Item): number => BASE_PRICE_BY_TYPE[item.type];
14	
15	const quotePremium = (step: Step): number =>
16	  step.items.reduce((sum, item) => sum + itemBasePrice(item), 0) + PROCESSING_FEE;
17	
18	export const runScenario = (input: unknown): unknown => {
19	  const scenario = input as Scenario;
20	  const results = scenario.steps.map((step) => ({ premium: quotePremium(step) }));
21	  return { results };
22	};
